import React from 'react';
import { useTheme } from '../context/ThemeContext';
import translations from '../translations';
import { FiMail, FiMapPin, FiClock, FiGithub, FiLinkedin } from 'react-icons/fi';

const Contact = () => {
  const { language } = useTheme();
  const t = translations[language].contact;

  const contactInfo = [
    { icon: FiMail, label: t.info.email, value: t.email },
    { icon: FiMapPin, label: t.info.location, value: t.location },
    { icon: FiClock, label: t.info.availability, value: t.availability }
  ];

  return (
    <section id="contact" className="contact">
      <div className="container">
        <div className="section-header">
          <h2 className="section-title">{t.title}</h2>
          <p className="section-subtitle">{t.subtitle}</p>
        </div>

        <div className="contact-centered">
          <p className="contact-description">{t.description}</p>

          <div className="contact-details">
            {contactInfo.map((item, index) => (
              <div key={index} className="contact-item">
                <div className="contact-item-icon">
                  <item.icon />
                </div>
                <div className="contact-item-text">
                  <span className="contact-item-label">{item.label}</span>
                  <span className="contact-item-value">{item.value}</span>
                </div>
              </div>
            ))}
          </div>

          <a
            href={`mailto:${t.email}`}
            className="btn btn-primary contact-cta"
          >
            <FiMail />
            {t.cta}
          </a>

          <div className="contact-social">
            <a href="https://github.com/username" target="_blank" rel="noopener noreferrer" className="social-link" aria-label="GitHub">
              <FiGithub />
            </a>
            <a href="https://linkedin.com/in/username" target="_blank" rel="noopener noreferrer" className="social-link" aria-label="LinkedIn">
              <FiLinkedin />
            </a>
          </div>
        </div>
      </div>
    </section>
  );
};

export default Contact;
